class DigitalTwinV2:
    def __init__(self, grid_topology, use_realistic_loss=True, use_marginal_pricing=True):
        self.grid_topology = grid_topology
        self.use_realistic_loss = use_realistic_loss
        self.use_marginal_pricing = use_marginal_pricing

    def edge_loss(self, edge, power_flow_kw):
        if self.use_realistic_loss:
            return transmission_loss_kw(power_flow_kw, edge["voltage_kv"], edge["resistance_ohms"])
        return power_flow_kw * edge["flat_loss_percent"]

    def current_price(self, demand_kw, renewable_output_kw):
        if self.use_marginal_pricing:
            return marginal_price(self.supply_bids, demand_kw - renewable_output_kw)
        return self.historical_price_lookup(demand_kw)
